const SUPABASE_URL = process.env.REACT_APP_SUPABASE_URL || "";
const SUPABASE_ANON_KEY = process.env.REACT_APP_SUPABASE_ANON_KEY || "";

const LOCAL_AUDITS_KEY = "garden-audit:audits";
const SUPABASE_TIMEOUT_MS = 8000;

function isSupabaseConfigured() {
  return /^https:\/\/.+\.supabase\.co$/.test(SUPABASE_URL) && SUPABASE_ANON_KEY.length > 20;
}

async function fetchWithTimeout(url, options = {}, timeoutMs = SUPABASE_TIMEOUT_MS) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(url, { ...options, signal: controller.signal });
  } finally {
    clearTimeout(timer);
  }
}

// Простой Supabase клиент (без зависимости от npm)
const supabase = {
  url: SUPABASE_URL,
  key: SUPABASE_ANON_KEY,
  headers: { "apikey": SUPABASE_ANON_KEY, "Authorization": `Bearer ${SUPABASE_ANON_KEY}`, "Content-Type": "application/json", "Prefer": "return=representation" },
  
  async query(table, params = {}) {
    let url = `${this.url}/rest/v1/${table}?`;
    if (params.select) url += `select=${params.select}&`;
    if (params.filters) params.filters.forEach(f => { url += `${f}&`; });
    if (params.order) url += `order=${params.order}&`;
    if (params.limit) url += `limit=${params.limit}&`;
    try {
      const res = await fetchWithTimeout(url, { headers: this.headers });
      return await res.json();
    } catch { return null; }
  },

  async insert(table, data) {
    try {
      const res = await fetchWithTimeout(`${this.url}/rest/v1/${table}`, {
        method: "POST", headers: this.headers, body: JSON.stringify(data),
      });
      const text = await res.text();
      if (!res.ok) { console.error(`Supabase INSERT ${table}:`, text); return null; }
      try { return JSON.parse(text); } catch { return null; }
    } catch (e) { console.error(`Supabase INSERT ${table}:`, e); return null; }
  },

  async upsert(table, data, onConflict) {
    const suffix = onConflict ? `?on_conflict=${encodeURIComponent(onConflict)}` : "";
    try {
      const res = await fetchWithTimeout(`${this.url}/rest/v1/${table}${suffix}`, {
        method: "POST",
        headers: { ...this.headers, "Prefer": "resolution=merge-duplicates,return=representation" },
        body: JSON.stringify(data),
      });
      const text = await res.text();
      if (!res.ok) { console.error(`Supabase UPSERT ${table}:`, text); return null; }
      try { return JSON.parse(text); } catch { return null; }
    } catch (e) { console.error(`Supabase UPSERT ${table}:`, e); return null; }
  },

  async rpc(fn, params = {}) {
    try {
      const res = await fetchWithTimeout(`${this.url}/rest/v1/rpc/${fn}`, {
        method: "POST", headers: this.headers, body: JSON.stringify(params),
      });
      return await res.json();
    } catch { return null; }
  },

  async uploadPhoto(bucket, path, file) {
    try {
      const res = await fetchWithTimeout(`${this.url}/storage/v1/object/${bucket}/${path}`, {
        method: "POST",
        headers: { "apikey": this.key, "Authorization": `Bearer ${this.key}`, "Content-Type": file.type, "x-upsert": "true" },
        body: file,
      });
      if (!res.ok) return null;
      return `${this.url}/storage/v1/object/public/${bucket}/${path}`;
    } catch { return null; }
  },

  async deletePhoto(bucket, paths) {
    try {
      await fetchWithTimeout(`${this.url}/storage/v1/object/${bucket}`, {
        method: "DELETE",
        headers: { ...this.headers, "Content-Type": "application/json" },
        body: JSON.stringify({ prefixes: paths }),
      });
    } catch {}
  }
};

