// Сжатие фото до среднего качества
function compressImage(file, maxWidth = 1200, quality = 0.6) {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        let w = img.width, h = img.height;
        if (w > maxWidth) { h = (h * maxWidth) / w; w = maxWidth; }
        canvas.width = w; canvas.height = h;
        canvas.getContext("2d").drawImage(img, 0, 0, w, h);
        canvas.toBlob((blob) => resolve(blob), "image/jpeg", quality);
      };
      img.src = e.target.result;
    };
    reader.readAsDataURL(file);
  });
}

function blobToDataUrl(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

function dataUrlToBlob(dataUrl) {
  const [meta, data] = dataUrl.split(",");
  const mime = meta.match(/data:(.*);base64/)?.[1] || "image/jpeg";
  const binary = atob(data);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new Blob([bytes], { type: mime });
}

function loadLocalAudits() {
  try {
    return JSON.parse(localStorage.getItem(LOCAL_AUDITS_KEY) || "[]");
  } catch {
    return [];
  }
}

function saveLocalAudits(audits) {
  try {
    localStorage.setItem(LOCAL_AUDITS_KEY, JSON.stringify(audits));
  } catch (error) {
    console.error("Не удалось сохранить аудиты локально:", error);
  }
}

function normalizePhotosForForm(photos = {}) {
  return Object.fromEntries(Object.entries(photos).map(([id, value]) => {
    if (typeof value === "string") return [id, { preview: value, dataUrl: value.startsWith("data:") ? value : null }];
    return [id, { ...value, preview: value.preview || value.dataUrl || "" }];
  }));
}

function getPhotoValue(photoData) {
  if (!photoData) return null;
  if (typeof photoData === "string") return photoData;
  return photoData.dataUrl || photoData.preview || null;
}

function getAnswerValue(answers, item) {
  if (!answers) return undefined;
  if (answers[item.id] !== undefined) return answers[item.id];
  const legacyId = item.legacyIds?.find(id => answers[id] !== undefined);
  return legacyId ? answers[legacyId] : undefined;
}

function getCommentValue(comments, item) {
  if (!comments) return "";
  if (comments[item.id]) return comments[item.id];
  const legacyId = item.legacyIds?.find(id => comments[id]);
  return legacyId ? comments[legacyId] : "";
}

async function saveAuditToSupabase(audit) {
  if (!USE_SUPABASE) return false;

  const auditId = String(audit.id);
  const auditRes = await supabase.upsert("audits", {
    id: auditId,
    shop_id: audit.shopId,
    auditor_id: audit.userId,
    barista_name: audit.baristaName,
    drink: audit.drink,
    food: audit.food,
    visit_date: audit.date,
    score_percent: audit.score,
    scored_points: audit.scoredPoints,
    total_points: audit.totalPoints,
  }, "id");

  if (!auditRes) return false;

  const photoUrls = {};
  for (const [qId, photoData] of Object.entries(audit.photos || {})) {
    if (typeof photoData === "string" && photoData.startsWith("http")) {
      photoUrls[qId] = photoData;
      continue;
    }

    const dataUrl = typeof photoData === "string" ? photoData : photoData?.dataUrl;
    const file = photoData?.file || (dataUrl ? dataUrlToBlob(dataUrl) : null);
    if (file) {
      const path = `audit-photos/${auditId}/${qId}.jpg`;
      const url = await supabase.uploadPhoto("audit-photos", path, file);
      if (url) photoUrls[qId] = url;
    }
  }

  const answerRows = [];
  AUDIT_SECTIONS.forEach(sec=>sec.items.forEach(it=>{
    const v = getAnswerValue(audit.answers, it); if (v===undefined) return;
    const row = {
      audit_id: auditId,
      question_id: it.id,
      answer_type: it.type,
      answer_yesno: null,
      answer_minutes: null,
      answer_rating: null,
      answer_text: null,
      passed: null,
      comment: getCommentValue(audit.comments, it) || null,
      photo_url: photoUrls[it.id] || null,
    };
    if (it.type==="yesno") { row.answer_yesno=v; row.passed=v==="yes"?true:v==="no"?false:null; }
    else if (it.type==="minutes") { row.answer_minutes=v; row.passed=v<=it.threshold; }
    else if (it.type==="rating") { row.answer_rating=v; }
    else if (it.type==="text") { row.answer_text=v; }
    answerRows.push(row);
  }));

  if (answerRows.length) {
    const answerRes = await supabase.upsert("audit_answers", answerRows, "audit_id,question_id");
    if (!answerRes) return false;
  }

  audit.photos = { ...(audit.photos || {}), ...photoUrls };
  audit.synced = true;
  return true;
}

