function generateDemoData() {
  const audits = [];
  const now = new Date();
  for (let i = 0; i < 120; i++) {
    const date = new Date(now); date.setDate(date.getDate() - Math.floor(Math.random() * 120));
    const shop = COFFEE_SHOPS[Math.floor(Math.random() * COFFEE_SHOPS.length)];
    const user = USERS[Math.floor(Math.random() * USERS.length)];
    const baristaNames = ["Анна","Мария","Олег","Дмитрий","Елена","Ксения","Алексей","Наталья","Ирина","Павел"];
    const drinks = ["Капучино","Латте","Американо","Раф","Флэт Уайт","Эспрессо","Мокко","V60","Матча Латте"];
    const foods = ["Круассан","Сэндвич","Чизкейк","Панини","Салат Цезарь","Блинчики","Тост с авокадо","Маффин"];
    const answers = {}, comments = {};
    AUDIT_SECTIONS.forEach(section => {
      section.items.forEach(item => {
        if (item.type === "yesno") { const r = Math.random(); answers[item.id] = r > 0.18 ? "yes" : r > 0.04 ? "no" : "na"; if (answers[item.id] === "no") comments[item.id] = "Замечание по данному пункту"; }
        else if (item.type === "minutes") { answers[item.id] = Math.floor(Math.random() * (item.threshold + 10)) + 1; if (answers[item.id] > item.threshold) comments[item.id] = "Превышено допустимое время"; }
        else if (item.type === "rating") { answers[item.id] = Math.floor(Math.random() * 3) + 3; }
        else if (item.type === "text") { answers[item.id] = item.id === "5.6" ? "Приятная атмосфера, вкусный кофе, улыбчивый бариста" : "Можно улучшить скорость обслуживания в часы пик"; }
      });
    });
    let scored = 0, total = 0;
    AUDIT_SECTIONS.slice(0, 4).forEach(s => { s.items.forEach(it => { const v = answers[it.id]; if (v === "na" || v === undefined) return; total++; if (it.type === "yesno" && v === "yes") scored++; if (it.type === "minutes" && v <= it.threshold) scored++; }); });
    audits.push({
      id: `audit-${i}`, shopId: shop.id, shopName: shop.name, city: shop.city,
      userId: user.id, userName: user.name, baristaName: baristaNames[Math.floor(Math.random() * baristaNames.length)],
      drink: drinks[Math.floor(Math.random() * drinks.length)], food: foods[Math.floor(Math.random() * foods.length)],
      date: date.toISOString(), answers, comments, score: total > 0 ? Math.round((scored / total) * 100) : 0, totalPoints: total, scoredPoints: scored,
    });
  }
  return audits.sort((a, b) => new Date(b.date) - new Date(a.date));
}

