// ============================================================
// UTILS
// ============================================================
function calcScore(answers) {
  let s = 0, t = 0;
  AUDIT_SECTIONS.slice(0, 4).forEach(sec => sec.items.forEach(it => {
    if (it.type !== "yesno" && it.type !== "minutes") return;
    t++;
    if (answers[it.id] === "yes") s++;
    if (it.type === "minutes" && answers[it.id] !== undefined && answers[it.id] <= it.threshold) s++;
  }));
  return { scored: s, total: t, percent: t > 0 ? Math.round((s / t) * 100) : 0 };
}
function scoreColor(s) { return s >= 85 ? "var(--sc-g)" : s >= 60 ? "var(--sc-m)" : "var(--sc-b)"; }
function fmtDate(d) { return new Date(d).toLocaleDateString("ru-RU",{day:"2-digit",month:"2-digit",year:"numeric"}); }
function fmtDateTime(d) { return new Date(d).toLocaleDateString("ru-RU",{day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit"}); }
function shortName(n) { return n.replace("Garden Coffee ",""); }

// ============================================================
// CIRCULAR PROGRESS
// ============================================================
function Ring({ value, size=80, sw=6 }) {
  const r=(size-sw)/2, c=2*Math.PI*r, off=c-(value/100)*c, col=scoreColor(value);
  return (
    <div style={{position:"relative",width:size,height:size,display:"inline-flex",alignItems:"center",justifyContent:"center"}}>
      {/* Добавили filter: drop-shadow для эффекта неона */}
      <svg width={size} height={size} style={{transform:"rotate(-90deg)", filter: `drop-shadow(0px 0px 8px ${col}60)`}}>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="var(--brd)" strokeWidth={sw}/>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={col} strokeWidth={sw} strokeDasharray={c} strokeDashoffset={off} strokeLinecap="round" style={{transition:"stroke-dashoffset 1s cubic-bezier(0.16, 1, 0.3, 1)"}}/>
      </svg>
      <div style={{position:"absolute",textAlign:"center"}}>
        <div style={{fontSize:size*.28,fontWeight:800,color:"var(--text)"}}>{value}%</div>
      </div>
    </div>
  );
}

function Badge({ score, size="md" }) {
  const col=scoreColor(score);
  const s={sm:{p:"2px 8px",fs:11},md:{p:"3px 10px",fs:13},lg:{p:"4px 14px",fs:15}}[size];
  return <span style={{display:"inline-flex",alignItems:"center",justifyContent:"center",padding:s.p,borderRadius:20,background:col+"18",color:col,fontSize:s.fs,fontWeight:700}}>{score}%</span>;
}

