function History({ audits, dark, onEdit }) {
  const [shopF, setShopF] = useState("all");
  const [search, setSearch] = useState("");
  const [expId, setExpId] = useState(null);
  const filtered = audits.filter(a=>{
    if(shopF!=="all"&&a.shopId!==parseInt(shopF))return false;
    if(search){const q=search.toLowerCase();return a.shopName.toLowerCase().includes(q)||a.baristaName.toLowerCase().includes(q)||(a.userName||"").toLowerCase().includes(q);}
    return true;
  });

  const selSt = {padding:"8px 30px 8px 12px",borderRadius:10,fontSize:13,border:"1.5px solid var(--brd)",background:"var(--bg-input)",color:"var(--text)",fontFamily:"'DM Sans',sans-serif",outline:"none",fontWeight:600,appearance:"none",WebkitAppearance:"none",backgroundImage:`url("data:image/svg+xml,%3Csvg width='12' height='12' viewBox='0 0 24 24' fill='none' stroke='%239CA3AF' stroke-width='2' xmlns='http://www.w3.org/2000/svg'%3E%3Cpolyline points='6 9 12 15 18 9'/%3E%3C/svg%3E")`,backgroundRepeat:"no-repeat",backgroundPosition:"right 10px center"};

  return (
    <div style={{padding:"0 0 80px"}}>
      <h1 style={{fontSize:24,fontWeight:700,color:"var(--text)",margin:"0 0 16px",fontFamily:"'DM Sans',sans-serif"}}>История проверок</h1>
      <div style={{display:"flex",gap:8,marginBottom:16,flexWrap:"wrap"}}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Поиск..." style={{flex:1,minWidth:140,padding:"8px 14px",borderRadius:10,fontSize:13,border:"1.5px solid var(--brd)",background:"var(--bg-input)",color:"var(--text)",fontFamily:"'DM Sans',sans-serif",outline:"none"}}/>
        <select value={shopF} onChange={e=>setShopF(e.target.value)} style={selSt}><option value="all">Все кофейни</option>{COFFEE_SHOPS.map(s=><option key={s.id} value={s.id}>{shortName(s.name)}</option>)}</select>
      </div>
      <p style={{fontSize:12,color:"var(--text-mut)",marginBottom:10}}>Найдено: {filtered.length}</p>

      {filtered.map(a=>(
        <div key={a.id} style={{background:"var(--bg-card)",borderRadius:14,marginBottom:8,border:"1px solid var(--brd-l)",boxShadow:"var(--shd)",overflow:"hidden"}}>
          <button onClick={()=>setExpId(expId===a.id?null:a.id)} style={{width:"100%",padding:"12px 14px",display:"flex",alignItems:"center",gap:10,background:"none",border:"none",cursor:"pointer",textAlign:"left"}}>
            <Badge score={a.score} size="sm"/>
            <div style={{flex:1}}>
              <div style={{fontSize:13,fontWeight:600,color:"var(--text)"}}>{shortName(a.shopName)}</div>
              <div style={{fontSize:11,color:"var(--text-mut)",marginTop:1}}>{fmtDate(a.date)} · {a.baristaName} · {a.userName||"—"}</div>
            </div>
            <span style={{color:"var(--text-mut)",transform:expId===a.id?"rotate(90deg)":"none",transition:"transform .2s"}}>{I.chevRight}</span>
          </button>
          {expId===a.id && (
            <div style={{padding:"0 14px 14px",borderTop:"1px solid var(--brd-l)"}}>
              <div style={{padding:"10px 0",display:"flex",gap:8,flexWrap:"wrap",fontSize:12}}>
                <span style={{padding:"3px 8px",borderRadius:6,background:"var(--bg-input)",color:"var(--text)"}}>☕ {a.drink}</span>
                {a.food && <span style={{padding:"3px 8px",borderRadius:6,background:"var(--bg-input)",color:"var(--text)"}}>🍽 {a.food}</span>}
                <button onClick={()=>generatePDFReport(a,"single")} style={{padding:"3px 8px",borderRadius:6,background:"var(--brand-bg)",color:"var(--brand-tx)",border:"none",cursor:"pointer",fontSize:12,fontWeight:600,fontFamily:"'DM Sans',sans-serif",display:"flex",alignItems:"center",gap:3}}>
                  {I.pdf} PDF
                </button>
                <button onClick={()=>onEdit(a)} style={{padding:"3px 8px",borderRadius:6,background:"var(--bg-input)",color:"var(--text)",border:"1px solid var(--brd)",cursor:"pointer",fontSize:12,fontWeight:600,fontFamily:"'DM Sans',sans-serif"}}>
                  Редактировать
                </button>
              </div>
              {AUDIT_SECTIONS.slice(0,4).map(sec=>(
                <div key={sec.id} style={{marginBottom:10}}>
                  <h4 style={{fontSize:12,fontWeight:700,color:"var(--brand-tx)",margin:"6px 0 4px"}}>{sec.title}</h4>
                  {sec.items.map(it=>{
                    const v=getAnswerValue(a.answers,it); const cm=getCommentValue(a.comments,it); const photoUrl=a.photos?.[it.id]; let pass=v==="na"?null:(it.type==="yesno"?v==="yes":v<=it.threshold);
                    return (
                      <div key={it.id} style={{display:"flex",alignItems:"flex-start",gap:6,padding:"3px 0",fontSize:12,lineHeight:1.5}}>
                        {v==="na"||v===undefined?<span style={{color:"var(--text-mut)",fontSize:10}}>—</span>:pass?<span style={{color:"var(--ok)"}}>{I.check}</span>:<span style={{color:"var(--err)"}}>{I.x}</span>}
                        <span style={{color:"var(--text)",flex:1}}>
                          {it.question}{it.type==="minutes"&&v!==undefined&&<span style={{fontWeight:600,marginLeft:4}}>({v} мин)</span>}
                          {cm&&<span style={{color:"var(--text-mut)",fontStyle:"italic",display:"block"}}>💬 {cm}</span>}
                          {photoUrl && <img src={photoUrl} alt="Фото" style={{width:120,height:90,objectFit:"cover",borderRadius:8,marginTop:4,border:"1px solid var(--brd)",display:"block"}}/>}
                        </span>
                      </div>
                    );
                  })}
                </div>
              ))}
              <h4 style={{fontSize:12,fontWeight:700,color:"var(--brand-tx)",margin:"6px 0 4px"}}>5. Впечатление</h4>
              {AUDIT_SECTIONS[4].items.filter(i=>i.type==="rating").map(it=>{
                const val = a.answers[it.id];
                const photoUrl = a.photos?.[it.id];
                return (
                  <div key={it.id} style={{padding:"4px 0",fontSize:12,borderBottom:"1px solid var(--brd-l)"}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                      <span style={{color:"var(--text)",flex:1}}>{it.question}</span>
                      <span style={{fontWeight:700,color:"var(--brand-tx)",whiteSpace:"nowrap"}}>{val != null ? `${val}/5` : "—"}</span>
                    </div>
                    {val != null && <div style={{color:"#F59E0B",fontSize:13,letterSpacing:2,marginTop:2}}>{"★".repeat(val)}{"☆".repeat(5-val)}</div>}
                    {photoUrl && <img src={photoUrl} alt="Фото" style={{width:120,height:90,objectFit:"cover",borderRadius:8,marginTop:4,border:"1px solid var(--brd)"}}/>}
                  </div>
                );
              })}
              {a.answers["5.6"]&&<p style={{fontSize:12,color:"var(--ok)",marginTop:6}}>👍 {a.answers["5.6"]}</p>}
              {a.answers["5.7"]&&<p style={{fontSize:12,color:"var(--err)"}}>👎 {a.answers["5.7"]}</p>}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

// ============================================================
// MAIN APP
// ============================================================
export default function GardenAuditApp() {
  const [dark, setDark] = useState(true);
  const [user, setUser] = useState(null);
  const [page, setPage] = useState("home");
  const [editingAudit, setEditingAudit] = useState(null);
  
  const [audits, setAudits] = useState(() => loadLocalAudits()); 
  
  const [mob, setMob] = useState(window.innerWidth<768);

  useEffect(()=>{ const h=()=>setMob(window.innerWidth<768); window.addEventListener("resize",h); return()=>window.removeEventListener("resize",h); },[]);

  // 2. ДОБРАВЛЯЕМ ВОТ ЭТОТ БЛОК КОДА (Загрузка данных из Supabase)
  useEffect(() => {
    if (!user) return;
    if (!USE_SUPABASE) {
      setAudits(loadLocalAudits());
      return;
    }

    async function fetchRealData() {
      try {
        const localAudits = loadLocalAudits();
        const pendingAudits = localAudits.filter(a => !a.synced);
        let syncedIds = [];
        if (pendingAudits.length) {
          for (const audit of pendingAudits) {
            const ok = await saveAuditToSupabase(audit);
            if (ok) syncedIds.push(audit.id);
          }
          if (syncedIds.length) {
            saveLocalAudits(localAudits.map(a => syncedIds.includes(a.id) ? { ...a, synced: true } : a));
          }
        }

        // Скачиваем аудиты, ответы и список пользователей из базы
        const dbAudits = await supabase.query("audits", { select: "*", order: "visit_date.desc", limit: 1000 }) || [];
        const dbAnswers = await supabase.query("audit_answers", { select: "*", limit: 10000 }) || [];
        const dbUsers = await supabase.query("auditors", { select: "id,name" }) || [];

        // Группируем ответы, комментарии и фото по ID аудита
        const answersMap = {};
        const commentsMap = {};
        const photosMap = {};

        dbAnswers.forEach(row => {
          if (!row.audit_id) return;
          if (!answersMap[row.audit_id]) {
            answersMap[row.audit_id] = {};
            commentsMap[row.audit_id] = {};
            photosMap[row.audit_id] = {};
          }
          const qId = row.question_id;
          
          if (row.answer_type === "yesno" && row.answer_yesno != null) answersMap[row.audit_id][qId] = row.answer_yesno;
          else if (row.answer_type === "minutes" && row.answer_minutes != null) answersMap[row.audit_id][qId] = row.answer_minutes;
          else if (row.answer_type === "rating" && row.answer_rating != null) answersMap[row.audit_id][qId] = row.answer_rating;
          else if (row.answer_type === "text" && row.answer_text != null) answersMap[row.audit_id][qId] = row.answer_text;

          if (row.comment) commentsMap[row.audit_id][qId] = row.comment;
          if (row.photo_url) photosMap[row.audit_id][qId] = row.photo_url;
        });

        // Собираем данные в тот формат, который понимают наши графики
        const formattedAudits = dbAudits.map(dbA => {
          const shop = COFFEE_SHOPS.find(s => s.id === dbA.shop_id) || {};
          const dbU = dbUsers.find(u => u.id === dbA.auditor_id);
          const localU = USERS.find(u => u.id === dbA.auditor_id);
          const auditorName = dbU?.name || localU?.name || "Неизвестный";

          return {
            id: dbA.id,
            shopId: dbA.shop_id,
            shopName: shop.name || "Неизвестная кофейня",
            city: shop.city || "",
            userId: dbA.auditor_id,
            userName: auditorName,
            baristaName: dbA.barista_name || "—",
            drink: dbA.drink || "—",
            food: dbA.food || "",
            date: dbA.visit_date,
            score: dbA.score_percent || 0,
            totalPoints: dbA.total_points || 0,
            scoredPoints: dbA.scored_points || 0,
            answers: answersMap[dbA.id] || {},
            comments: commentsMap[dbA.id] || {},
            photos: photosMap[dbA.id] || {},
            synced: true
          };
        });

        const remainingLocalAudits = localAudits.filter(a => !a.synced && !syncedIds.includes(a.id));
        const mergedAudits = [
          ...remainingLocalAudits,
          ...formattedAudits.filter(dbAudit => !remainingLocalAudits.some(localAudit => localAudit.id === dbAudit.id))
        ];

        setAudits(mergedAudits);
        saveLocalAudits(mergedAudits);
      } catch (error) {
        console.error("Ошибка при загрузке данных:", error);
        setAudits(loadLocalAudits());
      }
    }

    fetchRealData();
  }, [user]);
  // --- КОНЕЦ ДОБАВЛЕННОГО БЛОКА ---

  const handleNew = (audit) => {
    setAudits(p => {
      const next = [audit, ...p.filter(item => item.id !== audit.id)];
      saveLocalAudits(next);
      return next;
    });
    setEditingAudit(null);
  };

  const handleEdit = (audit) => {
    setEditingAudit(audit);
    setPage("audit");
  };

  const goPage = (nextPage) => {
    if (nextPage !== "audit") setEditingAudit(null);
    setPage(nextPage);
  };

  const startNewAudit = () => {
    setEditingAudit(null);
    if (user) localStorage.removeItem(`garden-audit:draft:${user.id}`);
    setPage("audit");
  };

  if (!user) return <LoginScreen onLogin={setUser} dark={dark}/>;

  const renderPage = () => {
    switch(page) {
      case "home": return <Dashboard audits={audits} user={user} dark={dark} go={goPage} startNewAudit={startNewAudit}/>;
      case "audit": return <AuditForm onSubmit={handleNew} dark={dark} user={user} initialAudit={editingAudit} onCancelEdit={()=>{setEditingAudit(null);setPage("history");}}/>;
      case "analytics": return <Analytics audits={audits} dark={dark}/>;
      case "history": return <History audits={audits} dark={dark} onEdit={handleEdit}/>;
      default: return <Dashboard audits={audits} user={user} dark={dark} go={goPage} startNewAudit={startNewAudit}/>;
    }
  };

  return (
    <div style={{...tv(dark),fontFamily:"'DM Sans',sans-serif",minHeight:"100vh",background:"var(--bg)",transition:"background .3s"}}>
      {!mob && <Side active={page} go={goPage} user={user} onLogout={()=>setUser(null)} dark={dark} toggle={()=>setDark(!dark)}/>}
      <main style={{marginLeft:mob?0:256,padding:mob?"14px 14px 0":"28px 36px 0",maxWidth:mob?"100%":940}}>
        {mob && (
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:18,padding:"6px 0"}}>
            <GardenLogo color={dark?BRAND.accent:BRAND.green} height={18}/>
            <div style={{display:"flex",gap:6,alignItems:"center"}}>
              <button onClick={()=>setDark(!dark)} style={{width:34,height:34,borderRadius:9,border:"1px solid var(--brd)",background:"var(--bg-card)",color:"var(--text-sec)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>{dark?I.sun:I.moon}</button>
              <button onClick={()=>setUser(null)} style={{width:34,height:34,borderRadius:9,border:"1px solid var(--brd)",background:"var(--bg-card)",color:"var(--text-sec)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>{I.logout}</button>
            </div>
          </div>
        )}
        {renderPage()}
      </main>
      {mob && <BNav active={page} go={goPage}/>}
      {!USE_SUPABASE && (
        <div style={{position:"fixed",bottom:mob?60:10,right:10,padding:"6px 12px",borderRadius:8,background:dark?"#333":"#FEF3C7",color:dark?"#F59E0B":"#92400E",fontSize:10,fontWeight:600,zIndex:200,boxShadow:"0 2px 8px rgba(0,0,0,.1)"}}>
          Локальный режим · работает без VPN
        </div>
      )}
    </div>
  );
}
